#include <stdio.h>
#include <stdint.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int64_t costs[N], flavors[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld %d", &costs[i], &flavors[i]);
        }
        int max_flavor = 0;
        for (int i = 0; i < N; i++) {
            int64_t sum = 0;
            for (int j = i; j < N; j++) {
                sum += costs[j];
                if (sum > K) break;
                int flavor = 0;
                for (int mask = 0; mask < (1 << (j - i + 1)); mask++) {
                    int curr_flavor = 0;
                    for (int k = 0; k < j - i + 1; k++) {
                        if ((mask & (1 << k)) != 0) {
                            curr_flavor ^= flavors[i + k];
                        }
                    }
                    max_flavor = (max_flavor > curr_flavor) ? max_flavor : curr_flavor;
                }
            }
        }
        printf("%d\n", max_flavor);
    }
    return 0;
}

