import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int K = scanner.nextInt();
            long[] costs = new long[N];
            int[] flavors = new int[N];
            for (int i = 0; i < N; i++) {
                costs[i] = scanner.nextLong();
                flavors[i] = scanner.nextInt();
            }
            int maxFlavor = 0;
            for (int i = 0; i < N; i++) {
                long sum = 0;
                for (int j = i; j < N; j++) {
                    sum += costs[j];
                    if (sum > K) break;
                    int flavor = 0;
                    for (int mask = 0; mask < (1 << (j - i + 1)); mask++) {
                        int currFlavor = 0;
                        for (int k = 0; k < j - i + 1; k++) {
                            if ((mask & (1 << k)) != 0) {
                                currFlavor ^= flavors[i + k];
                            }
                        }
                        maxFlavor = Math.max(maxFlavor, currFlavor);
                    }
                }
            }
            System.out.println(maxFlavor);
        }
    }
}

