const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, K] = readline().split(' ').map(Number);
    const costs = [];
    const flavors = [];
    for (let j = 0; j < N; j++) {
        const [cost, flavor] = readline().split(' ').map(Number);
        costs.push(cost);
        flavors.push(flavor);
    }
    let maxFlavor = 0;
    for (let j = 0; j < N; j++) {
        let sum = 0;
        for (let k = j; k < N; k++) {
            sum += costs[k];
            if (sum > K) break;
            let flavor = 0;
            for (let mask = 0; mask < (1 << (k - j + 1)); mask++) {
                let currFlavor = 0;
                for (let l = 0; l < k - j + 1; l++) {
                    if ((mask & (1 << l)) !== 0) {
                        currFlavor ^= flavors[j + l];
                    }
                }
                maxFlavor = Math.max(maxFlavor, currFlavor);
            }
        }
    }
    console.log(maxFlavor);
}

